아래 SQL 수행 후 최종 COUNT 값은?
```sql
CREATE TABLE 품목 (품목ID VARCHAR2(3), 단가 NUMBER);
-- 초기 데이터: 001 1000, 002 2000, 003 1000, 004 2000
BEGIN TRANSACTION;
INSERT INTO 품목 VALUES ('005', 2000);
COMMIT;
BEGIN TRANSACTION;
DELETE FROM 품목 WHERE 품목ID = '002';
BEGIN TRANSACTION;
UPDATE 품목 SET 단가 = 2000 WHERE 단가 = 1000;
ROLLBACK;
SELECT COUNT(품목ID) FROM 품목 WHERE 단가 = 2000;
```
